#include <stdio.h>
#include <stdlib.h>

#define N 200001

// Structure for adjacency list node
struct Node {
    int vertex;
    struct Node* next;
};

// Array of adjacency lists
struct Node* adj[N];

// Array to keep track of visited nodes
int vis[N];

// Function to create a new adjacency list node
struct Node* createNode(int v) {
    struct Node* newNode = (struct Node*)malloc(sizeof(struct Node));
    newNode->vertex = v;
    newNode->next = NULL;
    return newNode;
}

// Function to add an edge to a directed graph
void addEdge(int src, int dest) {
    // Add edge from src to dest
    struct Node* newNode = createNode(dest);
    newNode->next = adj[src];
    adj[src] = newNode;
}

// Depth First Search function
void dfs(int v) {
    if (vis[v]) {
        return; // If the node is already visited, do not process it
    }
    vis[v] = 1; // Mark the node as visited

    // Process the neighbors
    struct Node* temp = adj[v];
    while (temp) {
        int u = temp->vertex;
        dfs(u);
        temp = temp->next;
    }
}

int main() {
    int n, m;
    scanf("%d %d", &n, &m);

    // Initialize adjacency list and visited array
    for (int i = 0; i < N; i++) {
        adj[i] = NULL;
        vis[i] = 0;
    }

    // Read the edges
    while (m--) {
        int a, b;
        scanf("%d %d", &a, &b);
        addEdge(a, b); // Directed edge
    }

    dfs(1); // Start dfs from source: 1

    // Print reachable nodes
    for (int i = 1; i <= n; i++) {
        if (vis[i]) { // A node is reachable if it is marked visited
            printf("%d ", i);
        }
    }

    return 0;
}

code.Java:
import java.util.*;

class Main {
    static int N = 200001; 
    static List<Integer>[] adj = new ArrayList[N];
    static boolean[] vis = new boolean[N];

    // Depth-First Search function
    public static void dfs(int v) {
        if (vis[v]) {
            return;
        }
        vis[v] = true;

        // Traverse neighbors of vertex v
        for (int u : adj[v]) {
            dfs(u);
        }
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        int n = scanner.nextInt();
        int m = scanner.nextInt();

        // Initialize adjacency list
        for (int i = 1; i <= n; i++) {
            adj[i] = new ArrayList<>();
        }

        // Read and construct the graph edges
        while (m-- > 0) {
            int a = scanner.nextInt();
            int b = scanner.nextInt();
            adj[a].add(b); // Directed edge
        }

        dfs(1); // Start DFS from source: 1

        // Print reachable nodes
        for (int i = 1; i <= n; i++) {
            if (vis[i]) { // A node is reachable if it is marked visited
                System.out.print(i + " ");
            }
        }
    }
}

